  doc.setFillColor(255, 255, 255);
  doc.circle(W2 / 2, 24, 14, "F");
  doc.setFillColor(220, 20, 60);
  doc.circle(W2 / 2, 19, 10, "F");
  doc.setFillColor(0, 106, 78);
  doc.circle(W2 / 2, 29, 10, "F");
  doc.setFontSize(5);
  doc.setTextColor(255, 255, 255);
  doc.text("দল", W2 / 2, 24, { align: "center" });
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(11);
  doc.setFont("helvetica", "bold");
  doc.text(ORG_NAME_EN, W2 / 2, 41, { align: "center" });
  doc.setFontSize(7);
  doc.setFont("helvetica", "normal");
  doc.text(PARENT_ORG, W2 / 2, 48, { align: "center" });
  doc.setFillColor(245, 245, 240);
  doc.rect(0, 53, W2, pageH - 53, "F");
  doc.setTextColor(0, 106, 78);
  doc.setFontSize(13);
  doc.setFont("helvetica", "bold");
  doc.text("MEMBERSHIP CARD", W2 / 2, 63, { align: "center" });
  doc.setDrawColor(220, 20, 60);
  doc.setLineWidth(0.8);
  doc.line(20, 66, W2 - 20, 66);
  const photoX = 10;
  const photoY = 72;
  const photoW = 32;
  const photoH = 38;
