  doc.setFillColor(statusColor[0], statusColor[1], statusColor[2]);
  doc.roundedRect(10, y2, 35, 8, 2, 2, "F");
  doc.setFontSize(7);
  doc.setTextColor(255, 255, 255);
  doc.setFont("helvetica", "bold");
  doc.text(member.status.toUpperCase(), 27.5, y2 + 5.5, { align: "center" });
  doc.setFontSize(7);
  doc.setTextColor(100, 100, 100);
  doc.setFont("helvetica", "normal");
  doc.text(`ID: ${member.id.toString()}`, W2 - 10, y2 + 5.5, { align: "right" });
  y2 += 16;
  doc.setDrawColor(200, 200, 200);
  doc.setLineWidth(0.3);
  doc.line(10, y2, W2 - 10, y2);
  y2 += 6;
  doc.setFontSize(9);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(0, 106, 78);
  doc.text(ORG_NAME, W2 / 2, y2, { align: "center" });
  const sigY = pageH - 20;
  doc.setDrawColor(0, 106, 78);
  doc.setLineWidth(0.5);
  doc.line(W2 / 2 - 25, sigY, W2 / 2 + 25, sigY);
  doc.setFontSize(8);
  doc.setTextColor(0, 106, 78);
  doc.setFont("helvetica", "normal");
  doc.text(SIGNATURE_LABEL, W2 / 2, sigY + 5, { align: "center" });
  doc.setFillColor(0, 106, 78);
  doc.rect(0, pageH - 8, W2, 8, "F");
  doc.setFontSize(6);
  doc.setTextColor(255, 255, 255);
  doc.text(`${ORG_NAME} - সর্বস্বত্ব সংরক্ষিত`, W2 / 2, pageH - 3, {
    align: "center"
  });
